changeSet.sql:
ALTER TABLE policies ADD COLUMN IF NOT EXISTS document_id integer DEFAULT NULL;

ALTER TABLE policies ADD CONSTRAINT fk_policies_to_document FOREIGN KEY (document_id) REFERENCES documents (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE;

CREATE INDEX i_policies_document ON policies (document_id);

rollback.sql:
DROP INDEX IF EXISTS i_policies_document;
ALTER TABLE policies DROP CONSTRAINT IF EXISTS fk_policies_to_document;
ALTER TABLE policies DROP COLUMN IF EXISTS document_id;
